    <nav class="navbar">
      <div class="nav-brand">ClassroomLAN</div>
      <div class="nav-links">
        <a href="#/" :class="{ active: route === 'home' }" @click="route = 'home'">首页</a>
        <a href="#/transfer" :class="{ active: route === 'transfer' }" @click="route = 'transfer'">文件传输</a>
        <a href="#/chat" :class="{ active: route === 'chat' }" @click="route = 'chat'">群聊</a>
        <a href="#/games" :class="{ active: route === 'games' }" @click="route = 'games'">游戏大厅</a>
      </div>
      <div class="nav-status">
        <span class="status-badge" :class="nodeState.role.toLowerCase()">
          {{ nodeState.role }}
        </span>
        <span v-if="nodeState.peers > 0" class="peers-count">
          {{ nodeState.peers }} 人在线
        </span>
      </div>
    </nav>

    <main class="main-content">
      <!-- 首页 -->
      <div v-if="route === 'home'" class="page-home">
        <h1>欢迎使用 ClassroomLAN</h1>
        <div class="status-card" :class="nodeState.role.toLowerCase()">
          <div class="status-icon">{{ roleIcon }}</div>
          <div class="status-title">{{ roleTitle }}</div>
          <div class="status-desc">{{ roleDesc }}</div>
        </div>

        <!-- 用户信息设置 -->
        <div class="user-settings-card">
          <h3>个人信息设置</h3>
          <div class="setting-row">
            <label>昵称:</label>
            <input type="text" v-model="nickname" @change="updateUserInfo" placeholder="输入昵称" class="setting-input">
          </div>
          <div class="setting-row">
            <label>头像:</label>
            <div class="avatar-selector">
              <span v-for="i in 8" :key="i" :class="['avatar-option', { selected: avatar === String(i) }]" @click="avatar = String(i); updateUserInfo()">{{ i }}</span>
            </div>
          </div>
          <button @click="updateUserInfo" class="save-btn">保存</button>
        </div>

        <div class="quick-actions">
          <a href="#/transfer" class="action-card" @click="route = 'transfer'">
            <div class="action-icon">📁</div>
            <div class="action-title">文件传输</div>
            <div class="action-desc">与同学分享文件</div>
          </a>
          <a href="#/games" class="action-card" @click="route = 'games'">
            <div class="action-icon">🎮</div>
            <div class="action-title">游戏大厅</div>
            <div class="action-desc">一起玩游戏</div>
          </a>
        </div>
        <div class="info-card" v-if="nodeState.role === 'LEADER'">
          <h3>你的 IP 地址</h3>
          <div class="ip-address">{{ nodeState.selfIp || '获取中...' }}</div>
        </div>
      </div>

      <!-- 文件传输 -->
      <div v-if="route === 'transfer'" class="page-transfer">
        <h1>文件传输</h1>
        <div class="upload-area" @click="triggerUpload" @dragover.prevent="isDragging = true" @dragleave.prevent="isDragging = false" @drop.prevent="handleDrop" :class="{ dragover: isDragging }">
          <div class="upload-icon">📤</div>
          <div class="upload-text">点击或拖拽文件上传</div>
          <input type="file" ref="fileInput" @change="handleFile" style="display:none" multiple>
        </div>
        <div class="file-list" v-if="fileList.length > 0">
          <div class="file-item" v-for="f in fileList" :key="f.id">
            <div class="file-icon">📄</div>
            <div class="file-name">{{ f.name }}</div>
            <button class="download-btn" @click="downloadFile(f)">下载</button>
          </div>
        </div>
        <div v-else class="empty">暂无文件</div>
      </div>

      <!-- 群聊 -->
      <div v-if="route === 'chat'" class="page-chat">
        <h1>群聊</h1>
        <div class="chat-container">
          <div class="chat-online">
            <div class="online-header">在线 ({{ chatOnline }})</div>
            <div class="online-list">
              <div class="online-item" v-for="p in chatPlayers" :key="p">{{ p }}</div>
            </div>
          </div>
          <div class="chat-main">
            <div class="chat-messages" ref="chatMessagesRef">
              <div class="chat-message" v-for="(m, i) in chatMessages" :key="i" :class="{ system: m.isSystem }">
                <div class="msg-sender">{{ m.sender }}</div>
                <div class="msg-content">{{ m.content }}</div>
                <div class="msg-time">{{ new Date(m.timestamp).toLocaleTimeString() }}</div>
              </div>
            </div>
            <div class="chat-input" v-if="nodeState.role === 'LEADER'">
              <input type="text" v-model="playerName" placeholder="你的名字" class="name-input">
              <input type="text" v-model="chatInput" placeholder="输入消息..." @keyup.enter="sendChat" class="msg-input">
              <button @click="sendChat" class="send-btn">发送</button>
            </div>
            <div v-else class="chat-tip">请连接 Leader 后使用群聊</div>
          </div>
        </div>
      </div>

      <!-- 游戏大厅 -->
      <div v-if="route === 'games'" class="page-games">
        <h1>游戏大厅</h1>
        <div class="games-grid">
          <div class="game-card" @click="startGame('draw')">
            <div class="game-icon">🎨</div>
            <div class="game-name">你画我猜</div>
            <div class="game-desc">3~8人</div>
          </div>
          <div class="game-card" @click="startGame('quiz')">
            <div class="game-icon">❓</div>
            <div class="game-name">快问快答</div>
            <div class="game-desc">2~20人</div>
          </div>
          <div class="game-card" @click="startGame('werewolf')">
            <div class="game-icon">🕵️</div>
            <div class="game-name">谁是卧底</div>
            <div class="game-desc">4~12人</div>
          </div>
