      </div>
    </main>

    <!-- 在线用户列表 -->
    <div v-if="nodeState.role === 'LEADER' || nodeState.role === 'FOLLOWER'" class="online-panel">
      <div class="online-title">在线用户 ({{ onlineUsers.length }})</div>
      <div class="user-list">
        <div class="user-item" v-for="u in onlineUsers" :key="u.userId">
          <div class="user-avatar">{{ u.avatar }}</div>
          <div class="user-info">
            <div class="user-nickname">{{ u.nickname }}</div>
            <div class="user-ip">{{ u.ip }}</div>
          </div>
        </div>
      </div>
    </div>

    <div v-if="nodeState.role === 'LEADER' && onlineUsers.length <= 1" class="waiting-banner">
      等待同学加入... 当前在线: {{ onlineUsers.length }} 人
    </div>
  </div>
</template>

<script>
import { ref, reactive, computed, onMounted } from 'vue'

export default {
  name: 'App',
  setup() {
    const route = ref('home')
    const fileInput = ref(null)
    const isDragging = ref(false)
    const fileList = ref([])
    const chatMessages = ref([])
    const chatPlayers = ref([])
    const chatOnline = ref(0)
    const playerName = ref('')
    const chatInput = ref('')
    const chatMessagesRef = ref(null)

    // 用户信息
    const userId = ref('user_' + Math.random().toString(36).substring(2, 10))
    const nickname = ref('用户' + Math.floor(Math.random() * 1000))
    const avatar = ref('1')
    const onlineUsers = ref([])

    const nodeState = reactive({
      role: 'CANDIDATE',
      selfIp: '',
      leaderIp: '',
      peers: 0
    })

    const roleIcon = computed(() => {
      switch (nodeState.role) {
        case 'LEADER': return '👑'
        case 'FOLLOWER': return '👤'
        default: return '⏳'
      }
    })

    const roleTitle = computed(() => {
      switch (nodeState.role) {
        case 'LEADER': return '你是Leader'
        case 'FOLLOWER': return '已连接'
        default: return '正在识别...'
      }
    })

    const roleDesc = computed(() => {
      switch (nodeState.role) {
        case 'LEADER': return '其他同学可以通过你的 IP 连接'
        case 'FOLLOWER': return `已连接到 ${nodeState.leaderIp}`
        default: return '请稍候...'
      }
    })

    async function fetchStatus() {
      try {
        const res = await fetch('/api/status')
        const data = await res.json()
        nodeState.role = data.role
        nodeState.selfIp = data.selfIp
        nodeState.peers = data.peers || 0
      } catch (e) {
        console.error('fetchStatus error:', e)
      }
    }

    async function fetchOnlineUsers() {
      try {
        const res = await fetch('/api/users/online')
        onlineUsers.value = await res.json()
        chatPlayers.value = onlineUsers.value.map(u => u.nickname)
        chatOnline.value = onlineUsers.value.length
      } catch (e) {
        console.error('fetchOnlineUsers error:', e)
      }
    }

    async function registerUser() {
      try {
        await fetch('/api/users/register', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            userId: userId.value,
            nickname: nickname.value,
            avatar: avatar.value
          })
        })
      } catch (e) {
        console.error('registerUser error:', e)
      }
    }

    async function updateUserInfo() {
      try {
        await fetch('/api/users/register', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            userId: userId.value,
            nickname: nickname.value,
            avatar: avatar.value
          })
        })
        fetchOnlineUsers()
      } catch (e) {
        console.error('updateUserInfo error:', e)
      }
    }

    async function fetchFiles() {
      try {
        const res = await fetch('/api/files')
        fileList.value = await res.json()
      } catch (e) {
        console.error('fetchFiles error:', e)
      }
    }

    function triggerUpload() {
      fileInput.value?.click()
    }

    function handleFile(e) {
      const files = e.target.files
      for (const f of files) {
        uploadFile(f)
      }
    }

    function handleDrop(e) {
      isDragging.value = false
      const files = e.dataTransfer.files
      for (const f of files) {
        uploadFile(f)
      }
    }

    async function uploadFile(file) {
      const form = new FormData()
      form.append('file', file)
      try {
        await fetch('/api/upload', { method: 'POST', body: form })
        fetchFiles()
      } catch (e) {
        console.error('upload error:', e)
      }
    }

    async function downloadFile(file) {
      window.open(`/api/download/${file.id}`, '_blank')
    }

    async function fetchChatMessages() {
      try {
        const res = await fetch('/api/chat/messages')
        chatMessages.value = await res.json()
      } catch (e) {
        console.error('fetchChatMessages error:', e)
      }
    }

    async function fetchChatOnline() {
      try {
        const res = await fetch('/api/chat/online')
        const data = await res.json()
        chatOnline.value = data.count
        chatPlayers.value = data.players || []
      } catch (e) {
        console.error('fetchChatOnline error:', e)
      }
    }

    async function sendChat() {
      if (!playerName.value || !chatInput.value) return
      try {
        await fetch('/api/chat/send', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ playerName: playerName.value, content: chatInput.value })
        })
        chatInput.value = ''
        fetchChatMessages()
      } catch (e) {
        console.error('sendChat error:', e)
      }
    }

    // eslint-disable-next-line no-unused-vars
    function startGame(type) {
      alert('游戏功能需要连接 WebSocket，请稍后')
    }

    onMounted(() => {
      // 解析初始路由
      const hash = window.location.hash.slice(2)
      if (hash) route.value = hash

      // 监听 hash 变化
      window.addEventListener('hashchange', () => {
        route.value = window.location.hash.slice(2) || 'home'
      })

      // 获取状态后注册用户
      fetchStatus().then(() => {
        // 所有用户都需要注册（Leader 页面也需要）
        registerUser()
      })

      fetchFiles()
      fetchChatMessages()
      fetchChatOnline()
      fetchOnlineUsers()

      // 定期刷新
      setInterval(() => {
        if (nodeState.role === 'LEADER') {
          fetchStatus()
          fetchFiles()
        }
        fetchChatMessages()
        fetchChatOnline()
        fetchOnlineUsers()
      }, 3000)
    })

    return {
      route,
      nodeState,
      fileInput,
      isDragging,
      fileList,
      chatMessages,
      chatPlayers,
      chatOnline,
      playerName,
      chatInput,
      chatMessagesRef,
      onlineUsers,
      nickname,
      roleIcon,
      roleTitle,
      roleDesc,
      triggerUpload,
      handleFile,
      handleDrop,
      downloadFile,
      sendChat,
      fetchOnlineUsers,
      registerUser,
      updateUserInfo,
      startGame
    }
  }
}
</script>

